css:
.ps-map-stats { position: absolute; top: 1rem; right: 1rem; background: var(--pds-surface-layer); border: 1px solid var(--pds-border-subtle); border-radius: var(--pds-radius-sm); box-shadow: 0 2px 8px rgba(0,0,0,0.15); padding: var(--pds-space-2); z-index: 5; min-width: 160px; }
.ps-map-stats__grid { display: grid; grid-template-columns: 1fr 1fr; gap: var(--pds-space-2) var(--pds-space-4); margin: 0; }
.ps-map-stats__cell { display: flex; flex-direction: column; gap: 0.125rem; }
.ps-map-stats__label { font-size: 0.6875rem; text-transform: uppercase; letter-spacing: 0.06em; color: var(--pds-text-secondary); }
.ps-map-stats__value { font-size: 1.25rem; font-weight: 700; color: var(--pds-text-primary); margin: 0; transition: color var(--pds-duration-base) ease; }
